'use client';

import { useState, useEffect, useRef } from 'react';
import { useRouter } from 'next/navigation';
import { useAuth } from '@/context/AuthContext';
import {
  collection, query, where, onSnapshot, addDoc, orderBy,
  doc, updateDoc, serverTimestamp
} from 'firebase/firestore';
import { db } from '@/lib/firebase';
import { Chat, Message } from '@/lib/types';
import BottomNav from '@/components/BottomNav';

export default function ChatPage() {
  const { user, profile, loading } = useAuth();
  const router = useRouter();
  const [chats, setChats] = useState<Chat[]>([]);
  const [openChat, setOpenChat] = useState<Chat | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!loading && !user) router.push('/auth');
  }, [user, loading, router]);

  // Real-time chats list
  useEffect(() => {
    if (!user) return;
    const q = query(
      collection(db, 'chats'),
      where('participants', 'array-contains', user.uid)
    );
    const unsub = onSnapshot(q, (snap) => {
      const list = snap.docs.map((d) => d.data() as Chat);
      list.sort((a, b) => new Date(b.lastMessageAt).getTime() - new Date(a.lastMessageAt).getTime());
      setChats(list);
    });
    return () => unsub();
  }, [user]);

  // Real-time messages for open chat
  useEffect(() => {
    if (!openChat) return;
    const q = query(
      collection(db, 'messages'),
      where('chatId', '==', openChat.id),
      orderBy('timestamp', 'asc')
    );
    const unsub = onSnapshot(q, (snap) => {
      const msgs = snap.docs.map((d) => ({ id: d.id, ...d.data() } as Message));
      setMessages(msgs);
      setTimeout(() => messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' }), 100);
    });
    return () => unsub();
  }, [openChat]);

  // Fetch NIM suggestions when messages change
  useEffect(() => {
    if (!openChat || messages.length === 0) return;
    const fetchSuggestions = async () => {
      try {
        const res = await fetch('/api/nim', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            action: 'chat-suggest',
            payload: {
              messages: messages.slice(-6).map((m) => ({
                sent: m.senderId === user?.uid,
                senderCodeName: m.senderCodeName,
                text: m.text,
              })),
              chatName: openChat.type === 'individual'
                ? Object.values(openChat.participantNames).find((n) => n !== profile?.codeName) ?? 'them'
                : openChat.projectName ?? 'group',
              isGroup: openChat.type === 'group',
            },
          }),
        });
        if (res.ok) {
          const { suggestions: s } = await res.json();
          setSuggestions(s || []);
        }
      } catch { /* graceful degradation */ }
    };
    const timer = setTimeout(fetchSuggestions, 800);
    return () => clearTimeout(timer);
  }, [messages, openChat, user?.uid, profile?.codeName]);

  const sendMessage = async () => {
    if (!input.trim() || !openChat || !user || !profile) return;
    const text = input.trim();
    setInput('');
    setSuggestions([]);

    try {
      await addDoc(collection(db, 'messages'), {
        chatId: openChat.id,
        senderId: user.uid,
        senderCodeName: profile.codeName,
        text,
        timestamp: new Date().toISOString(),
        type: 'text',
      });
      await updateDoc(doc(db, 'chats', openChat.id), {
        lastMessage: text,
        lastMessageAt: new Date().toISOString(),
      });
    } catch (err) {
      console.error(err);
    }
  };

  const getInitials = (name: string) =>
    name.split(/\s+/).map((w) => w[0]).join('').slice(0, 2).toUpperCase();

  const getPartnerName = (chat: Chat) => {
    if (chat.type === 'group') return chat.projectName ?? 'Group';
    return Object.values(chat.participantNames).find((n) => n !== profile?.codeName) ?? 'Match';
  };

  const timeAgo = (iso: string) => {
    const diff = Date.now() - new Date(iso).getTime();
    if (diff < 60000) return 'now';
    if (diff < 3600000) return `${Math.floor(diff / 60000)}m`;
    if (diff < 86400000) return `${Math.floor(diff / 3600000)}h`;
    return `${Math.floor(diff / 86400000)}d`;
  };

  if (loading) return <div className="loading-page"><div className="spinner" /></div>;

  // ── Open Chat View ──────────────────────────────────────────────────────────
  if (openChat) {
    const partnerName = getPartnerName(openChat);
    return (
      <div className="app-shell" style={{ height: '100vh', overflow: 'hidden' }}>
        <div className="chat-view">
          <div className="chat-view-header">
            <button className="back-btn" onClick={() => { setOpenChat(null); setSuggestions([]); }}>←</button>
            <div
              className={`chat-avatar ${openChat.type === 'group' ? 'group' : ''}`}
              style={{ width: 38, height: 38, fontSize: 14 }}
            >
              {getInitials(partnerName)}
            </div>
            <div className="chat-view-info">
              <div className="chat-view-name">{partnerName}</div>
              <div className="chat-view-status">
                {openChat.type === 'group' ? `${openChat.participants.length} members` : 'Anonymous collaborator'}
              </div>
            </div>
            <div className="chat-view-actions">
              <button className="call-btn">📞</button>
              <button className="call-btn">📹</button>
            </div>
          </div>

          <div className="messages-area">
            {messages.map((m) => (
              <div key={m.id} className={`msg ${m.senderId === user?.uid ? 'sent' : m.type === 'system' ? 'system' : 'recv'}`}>
                {m.type !== 'system' && m.senderId !== user?.uid && openChat.type === 'group' && (
                  <div className="msg-from">{m.senderCodeName}</div>
                )}
                {m.text}
                {m.type !== 'system' && (
                  <div className="msg-time">
                    {new Date(m.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </div>
                )}
              </div>
            ))}
            {messages.length === 0 && (
              <div style={{ textAlign: 'center', color: 'var(--subtle)', fontSize: 13, marginTop: 40 }}>
                Start the conversation ✨
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          {suggestions.length > 0 && (
            <div className="nim-suggestions">
              {suggestions.map((s, i) => (
                <button key={i} className="nim-chip" onClick={() => { setInput(s); setSuggestions([]); }}>
                  {s}
                </button>
              ))}
            </div>
          )}

          <div className="chat-input-row">
            <input
              className="chat-input"
              placeholder="Message..."
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && sendMessage()}
            />
            <button className="send-btn" onClick={sendMessage}>➤</button>
          </div>
        </div>
      </div>
    );
  }

  // ── Chat List ───────────────────────────────────────────────────────────────
  const dms = chats.filter((c) => c.type === 'individual');
  const groups = chats.filter((c) => c.type === 'group');

  return (
    <div className="app-shell">
      <header className="c-header">
        <span className="c-logo">Campus<span>Link</span></span>
      </header>

      <div className="page-content">
        <div className="chat-wrap">
          <h1 className="section-title" style={{ marginBottom: 16 }}>Messages</h1>

          {chats.length === 0 ? (
            <div style={{ textAlign: 'center', padding: '60px 0', color: 'var(--subtle)' }}>
              <div style={{ fontSize: 48, marginBottom: 12 }}>💬</div>
              <p>No chats yet. Get swiping to match!</p>
            </div>
          ) : (
            <>
              {dms.length > 0 && (
                <>
                  <div className="chat-section-title">Direct Messages</div>
                  {dms.map((c) => {
                    const name = getPartnerName(c);
                    return (
                      <div key={c.id} className="chat-item" onClick={() => setOpenChat(c)}>
                        <div className="chat-avatar">
                          {getInitials(name)}
                          <div className="online-dot" />
                        </div>
                        <div className="chat-info">
                          <div className="chat-name">{name}</div>
                          <div className="chat-preview">{c.lastMessage}</div>
                        </div>
                        <div className="chat-meta">
                          <div className="chat-time">{timeAgo(c.lastMessageAt)}</div>
                        </div>
                      </div>
                    );
                  })}
                </>
              )}

              {groups.length > 0 && (
                <>
                  <div className="divider" />
                  <div className="chat-section-title">Group Chats</div>
                  {groups.map((c) => {
                    const name = getPartnerName(c);
                    return (
                      <div key={c.id} className="chat-item" onClick={() => setOpenChat(c)}>
                        <div className="chat-avatar group">{getInitials(name)}</div>
                        <div className="chat-info">
                          <div className="chat-name">{name}</div>
                          <div className="chat-preview">{c.lastMessage}</div>
                        </div>
                        <div className="chat-meta">
                          <div className="chat-time">{timeAgo(c.lastMessageAt)}</div>
                        </div>
                      </div>
                    );
                  })}
                </>
              )}
            </>
          )}
        </div>
      </div>

      <BottomNav />
    </div>
  );
}
